<template>
  <div>
    <div
      v-for="fish in fishes"
      :key="fish.id"
      class="fish"
      :style="{
        left: fish.left + 'px',
        animationDuration: fish.duration + 's',
        backgroundImage: `url(${fish.image})`,
        backgroundSize: 'cover',
      }"
    ></div>
    <div
      v-for="splash in splashes"
      :key="splash.id"
      class="splash"
      :style="{
        left: splash.left + 'px',
        top: splash.top + 'px',
        backgroundImage: `url(${splash.image})`,
        backgroundSize: 'cover',
      }"
    ></div>
  </div>
</template>

<script>
export default {
  name: 'FishComponent',
  data() {
    return {
      fishes: [],
      splashes: [],
      fishImages: [
        '/image/fish/1.gif',
        '/image/fish/2.gif',
        '/image/fish/3.gif',
        '/image/fish/4.gif',
        '/image/fish/5.gif',
        '/image/fish/6.gif',
        '/image/fish/7.gif',
        '/image/fish/11.gif',
        '/image/fish/12.gif',
      ],
      splashImages: [
        '/image/fish/8.gif',
        '/image/fish/9.gif',
        '/image/fish/10.gif',
        '/image/fish/14.gif',
      ],
    };
  },
  methods: {
    addFish() {
      const id = Date.now();
      const newFish = {
        id,
        left: 40 + Math.random() * (window.innerWidth - 80), // 限制左右边距为 40px
        duration: 3 + Math.random() * 5,
        image: this.fishImages[Math.floor(Math.random() * this.fishImages.length)],
      };
      this.fishes.push(newFish);

      // Detect when fish reaches the bottom (wave position)
      setTimeout(() => {
        this.createSplash(newFish.left);
        this.fishes = this.fishes.filter((fish) => fish.id !== id);
      }, newFish.duration * 1000);
    },
    createSplash(left) {
      const id = Date.now();
      const newSplash = {
        id,
        left,
        top: window.innerHeight - 100, // Adjust to wave height
        image: this.splashImages[Math.floor(Math.random() * this.splashImages.length)],
      };
      this.splashes.push(newSplash);

      // Remove splash after animation ends
      setTimeout(() => {
        this.splashes = this.splashes.filter((splash) => splash.id !== id);
      }, 1000); // Splash duration
    },
  },
  mounted() {
    this.fishInterval = setInterval(this.addFish, 1000);
  },
  beforeUnmount() {
    clearInterval(this.fishInterval);
  },
};
</script>

<style scoped>
@import '/public/csspro/fish.css';

.fish {
  position: absolute;
  top: 0;
  width: 50px;
  height: 50px;
  pointer-events: none;
  animation: fish-move linear;
}

@keyframes fish-move {
  0% {
    transform: translateY(0);
  }
  100% {
    transform: translateY(calc(100vh - 50px)); /* Move fish to just above the bottom */
  }
}

.splash {
  position: absolute;
  width: 50px;
  height: 50px;
  pointer-events: none;
}

/* 防止页面滚动条 */
html,
body {
  margin: 0;
  padding: 0;
  overflow: hidden; /* 禁用滚动条 */
  height: 100%; /* 确保视口高度 */
}

</style>

